diff --git a/test/webpackImporter-options.test.js b/test/webpackImporter-options.test.js
new file mode 100644
index 0000000..1bf8415
--- /dev/null
+++ b/test/webpackImporter-options.test.js
@@ -0,0 +1,49 @@
+import {
+  compile,
+  getCodeFromBundle,
+  getCodeFromLess,
+  getCompiler,
+  getErrors,
+  getWarnings,
+} from './helpers';
+
+describe('webpackImporter option', () => {
+  it('not specify webpackImporter option', async () => {
+    const testId = './import-webpack.less';
+    const compiler = getCompiler(testId);
+    const stats = await compile(compiler);
+    const codeFromBundle = getCodeFromBundle(stats, compiler);
+    const codeFromLess = await getCodeFromLess(testId);
+
+    expect(codeFromBundle.css).toBe(codeFromLess.css);
+    expect(codeFromBundle.css).toMatchSnapshot('css');
+    expect(getWarnings(stats)).toMatchSnapshot('warnings');
+    expect(getErrors(stats)).toMatchSnapshot('errors');
+  });
+
+  it('webpackImporter option is true', async () => {
+    const testId = './import-webpack.less';
+    const compiler = getCompiler(testId, {
+      webpackImporter: true,
+    });
+    const stats = await compile(compiler);
+    const codeFromBundle = getCodeFromBundle(stats, compiler);
+    const codeFromLess = await getCodeFromLess(testId);
+
+    expect(codeFromBundle.css).toBe(codeFromLess.css);
+    expect(codeFromBundle.css).toMatchSnapshot('css');
+    expect(getWarnings(stats)).toMatchSnapshot('warnings');
+    expect(getErrors(stats)).toMatchSnapshot('errors');
+  });
+
+  it('webpackImporter option is false', async () => {
+    const testId = './import-webpack.less';
+    const compiler = getCompiler(testId, {
+      webpackImporter: false,
+    });
+    const stats = await compile(compiler);
+
+    expect(getWarnings(stats)).toMatchSnapshot('warnings');
+    expect(getErrors(stats)).toMatchSnapshot('errors');
+  });
+});

diff --git a/test/loader.test.js b/test/loader.test.js
index e8076eb..37ecb68 100644
--- a/test/loader.test.js
+++ b/test/loader.test.js
@@ -727,4 +727,50 @@ describe('loader', () => {
     expect(getWarnings(stats)).toMatchSnapshot('warnings');
     expect(getErrors(stats)).toMatchSnapshot('errors');
   });
+
+  it('should work loaderContext in less plugins', async () => {
+    let contextInClass;
+    let contextInObject;
+
+    // eslint-disable-next-line global-require
+    class Plugin extends require('less').FileManager {
+      constructor(less) {
+        super();
+
+        if (typeof less.webpackLoaderContext !== 'undefined') {
+          contextInClass = true;
+        }
+      }
+    }
+
+    class CustomClassPlugin {
+      // eslint-disable-next-line class-methods-use-this
+      install(less, pluginManager) {
+        pluginManager.addFileManager(new Plugin(less));
+      }
+    }
+
+    const customObjectPlugin = {
+      install(less) {
+        if (typeof less.webpackLoaderContext !== 'undefined') {
+          contextInObject = true;
+        }
+      },
+    };
+
+    const testId = './basic-plugins.less';
+    const compiler = getCompiler(testId, {
+      lessOptions: {
+        plugins: [new CustomClassPlugin(), customObjectPlugin],
+      },
+    });
+    const stats = await compile(compiler);
+    const codeFromBundle = getCodeFromBundle(stats, compiler);
+
+    expect(contextInClass).toBe(true);
+    expect(contextInObject).toBe(true);
+    expect(codeFromBundle.css).toMatchSnapshot('css');
+    expect(getWarnings(stats)).toMatchSnapshot('warnings');
+    expect(getErrors(stats)).toMatchSnapshot('errors');
+  });
 });

